# Representative lifecycle guardrail for an incident MCP connector.
ALLOWED_TRANSITIONS = {
    "new": {"acknowledged"},
    "acknowledged": {"mitigated", "escalated"},
    "escalated": {"mitigated"},
    "mitigated": {"resolved"},
    "resolved": {"postmortem"},
}

def can_transition(current: str, desired: str) -> bool:
    return desired in ALLOWED_TRANSITIONS.get(current, set())

print(can_transition("new", "resolved"))       # False: too much authority for one jump.
print(can_transition("new", "acknowledged"))  # True: normal first response.

# Representative MCP tool definitions. Not an official IcM schema.
incident_tools = [
    {
        "name": "query_incidents",
        "description": "Find incidents by service, severity, status, or time range.",
        "inputSchema": {
            "type": "object",
            "properties": {
                "service": {"type": "string"},
                "severity": {"type": "string"},
                "status": {"type": "string"},
            },
        },
    },
    {
        "name": "acknowledge_incident",
        "description": "Mark an incident as acknowledged by the current authorized identity.",
        "inputSchema": {"type": "object", "required": ["incident_id"]},
    },
]
print([tool["name"] for tool in incident_tools])

# Representative MCP tools/call payloads. Not official IcM JSON.
examples = [
    {
        "jsonrpc": "2.0",
        "id": 1,
        "method": "tools/call",
        "params": {
            "name": "query_incidents",
            "arguments": {"service": "payments", "severity": "Sev2", "status": "active"},
        },
    },
    {
        "jsonrpc": "2.0",
        "id": 2,
        "method": "tools/call",
        "params": {"name": "get_incident", "arguments": {"incident_id": "INC123456"}},
    },
    {
        "jsonrpc": "2.0",
        "id": 3,
        "method": "tools/call",
        "params": {
            "name": "add_discussion",
            "arguments": {
                "incident_id": "INC123456",
                "message": "Representative note: rollback started after human approval.",
            },
        },
    },
]
for payload in examples:
    print(payload["params"]["name"], payload["params"]["arguments"])

# Representative approval gate around a write action.
def require_approval(tool_name: str) -> bool:
    write_tools = {"create_incident", "update_incident", "add_discussion", "acknowledge_incident", "resolve_incident"}
    return tool_name in write_tools

proposed_call = {
    "tool": "acknowledge_incident",
    "arguments": {"incident_id": "INC123456"},
    "reason": "User asked me to acknowledge the active payments incident.",
}

if require_approval(proposed_call["tool"]):
    print("Show this exact call to a human approver before execution:")
    print(proposed_call)
else:
    print("Read-only call may proceed under policy.")
